const m=document.getElementById("menu")
const c=document.getElementById("content")
const s=document.getElementById("search")

async function loadArticles(){

let r=await fetch("articles/index.json")
let d=await r.json()

renderMenu(d)

}

function renderMenu(data){

m.innerHTML=""

data.forEach(a=>{

let item=document.createElement("div")

item.className="menu-item"

item.innerText=a.title

item.onclick=()=>loadArticle(a.file)

m.appendChild(item)

})

}

async function loadArticle(file){

let r=await fetch("articles/"+file)

let d=await r.json()

c.innerHTML="<h2>"+d.title+"</h2>"+d.content

}

s.addEventListener("input",async function(){

let r=await fetch("articles/index.json")

let d=await r.json()

let f=d.filter(a=>a.title.toLowerCase().includes(s.value.toLowerCase()))

renderMenu(f)

})

loadArticles()
